@ignore_charray_deprecation
class TestWhitespace:
    def test1(self):
        A = np.array([['abc ', '123  '],
                      ['789 ', 'xyz ']]).view(np.char.chararray)
        B = np.array([['abc', '123'],
                      ['789', 'xyz']]).view(np.char.chararray)
        assert_(np.all(A == B))
        assert_(np.all(A >= B))
        assert_(np.all(A <= B))
        assert_(not np.any(A > B))
        assert_(not np.any(A < B))
        assert_(not np.any(A != B))

